import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "10-hooldusviga-mis-tapavad-vanema-auto-mootori";
const META_TITLE = "10 hooldusviga, mis tapavad vanema auto mootori enne tähtaega";
const META_DESCRIPTION =
  "Toome välja kümme kriitilist hooldusviga, mis lühendavad vanema auto mootori eluiga: õli, jahutus, filtrid, lekked ja sõiduharjumused.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "hooldusvead, vanem auto, mootori eluiga",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function Blog10HooldusvigaMisTapavadVanemaAutoMootori() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-10-hooldusviga-mis-tapavad-vanema-auto-mootori",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">10 hooldusviga, mis tapavad vanema auto mootori enne tähtaega</Heading>

          <p>
            Vanem auto ei sure „lihtsalt vanadusse“. Enamasti teevad töö ära konkreetsed <strong>hooldusvead</strong>, mis
            kogunevad aastate jooksul. Allpool on 10 tüüpilist apsu, mis lühendavad mootori eluiga oluliselt.
          </p>

          <Heading as="h2">1. Õlivahetuse venitamine „kuni aega saan“</Heading>
          <p>
            Üle läinud <strong>õlivahetusintervall</strong> on kõige klassikalisem mootoritapja. Väsinud õli kaotab määrimis- ja
            puhastusvõime ning turbo- ja laagri kahjustus on vaid aja küsimus.
          </p>

          <Heading as="h2">2. Vale või liiga vedel mootoriõli</Heading>
          <p>
            Vanale mootorile super-õhuke õli „kütuse kokkuhoiuks“ on halb plaan. Madal viskoossus = madal õlirõhk ja suurem
            õlikulu. Vali õli vastavalt mootori seisukorrale, mitte ainult reklaamile.
          </p>

          <Heading as="h2">3. Jahutusvedeliku mittevahetamine</Heading>
          <p>
            Vana jahutusvedelik muutub söövitavaks, põhjustab korrosiooni ja ummistab kanaleid. Tulemuseks ülekuumenemine ja
            plokikaane- või plokikahjustused.
          </p>

          <Heading as="h2">4. Lekete ignoreerimine</Heading>
          <p>
            „Natuke higistab“ muutub ajas „valab korralikult“. Õli- ja jahutusvedeliku lekked viivad lõpuks madala taseme ja
            rõhu kadumiseni. Vanal autol ei ole ükski leke „normaalne“.
          </p>

          <Heading as="h2">5. Filtreid vahetatakse harva või üldse mitte</Heading>
          <p>
            Ummistunud <strong>õlifilter, õhufilter ja kütusefilter</strong> tõstavad koormust mootorile ja kütusesüsteemile.
            Filtrid on odavad, mootor mitte.
          </p>

          <Heading as="h2">6. Pidev lühike linnasõit ilma kompensatsioonita</Heading>
          <p>
            Lühikesed otsad ei lase mootoril töötemperatuurini jõuda. Õli ei saa niiskust välja, tekib korrosioon ja setted.
            Lahendus: tihedam õlivahetus ja aeg-ajalt pikemad sõidud.
          </p>

          <Heading as="h2">7. Ülekuumenemise episoodide ignoreerimine</Heading>
          <p>
            Kui temperatuurinäidik käib punases ja omanik lihtsalt „sõidab edasi“, on plokikaane remont vaid aja küsimus.
            Ülekuumenemine on signaal kohe peatuda, mitte „jõuan sihtkohta ära“.
          </p>

          <Heading as="h2">8. Keti- ja rihmahoolduse edasilükkamine</Heading>
          <p>
            Vanadel autodel võivad <strong>hammasrihm ja kett</strong> juba lähedal olla oma piiri. Kui keti pinguti, rullikud
            või rihm ise läbi annavad, võib tagajärg olla ventiilide ja kolvide kokkupõrge.
          </p>

          <Heading as="h2">9. Mootori häälte ignoreerimine</Heading>
          <p>
            Tiksumine, kolin ja metalliline heli ei ole „vanale autole normaalne“. Need on varajased signaalid, mida kuulates on
            remont odav; neid ignoreerides muutub see kap remontiks.
          </p>

          <Heading as="h2">10. „Lisame lihtsalt paksu õli ja sõidame edasi“ suhtumine</Heading>
          <p>
            Paks õli ei lahenda kulunud mootori probleeme, vaid maskeerib sümptomeid. Ilma diagnostika ja tegelike põhjuste
            kõrvaldamiseta on see lühiajaline võit ja pikaajaline kaotus.
          </p>

          <Heading as="h2">Kokkuvõte: distsipliin remonti ei tapa, selle puudumine tapab</Heading>
          <p>
            <strong>Vanema auto mootori eluiga</strong> sõltub palju rohkem omanikust kui läbisõidust. Kui vältida neid kümmet
            tüüpilist hooldusviga, on suur võimalus, et mootor kestab oluliselt kauem kui statistika seda eeldaks.
          </p>
        </article>
      </main>
    </div>
  );
}

