import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "soonrihm-generaator-ja-roolivoim";
const META_TITLE = "Soonrihm, generaator ja roolivõim – miks „sirisev rihm“ ei ole süütu?";
const META_DESCRIPTION =
  "Selgitame, miks soonrihma sirin või vilin on märk probleemist, mis võib jätta su ilma laadimisest, roolivõimust ja kliimast kõige ebasobivamal hetkel.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "soonrihm, generaator, roolivõim", 
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogSoonrihmGeneraatorJaRoolivoim() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-soonrihm-generaator-ja-roolivoim",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Soonrihm, generaator ja roolivõim – miks „sirisev rihm“ ei ole süütu?</Heading>

          <p>
            Paljud juhid harjuvad sellega, et külma mootoriga teeb rihm <strong>vilisevat või sirisevat heli</strong>. „Las soojeneb, siis kaob ära“ ei ole tehniline lahendus. Soonrihm käitab elutähtsaid agregaate: <strong>generaatorit, roolivõimu ja kliimakompressorit</strong>.
          </p>

          <Heading as="h2">Mida soonrihm tegelikult teeb?</Heading>
          <p>
            Üks rihm juhib generaatorit, roolivõimu pumpa, kliimakompressorit ja mõnel mootoril ka veepumpa. Kui see rihm seiskub, kaovad ka kõik need funktsioonid.
          </p>

          <Heading as="h2">Miks rihm viliseb?</Heading>
          <p>
            Põhjused on veninud rihm, vigane pinguti, väsinud rullikud või õli/jahutusvedelik rihmaratastel. Iga neist tähendab, et kuskil <strong>libiseb detail ja töötab piiripeal</strong>.
          </p>

          <Heading as="h2">Mis juhtub, kui soonrihm puruneb?</Heading>
          <p>
            Kaotad kohe <strong>laadimise</strong>, roolivõimu toe ja kliima ning mõnel konstruktsioonil ka jahutuse. See võib juhtuda sõna otseses mõttes keset sõitu kõige valemal hetkel.
          </p>

          <Heading as="h2">Miks „natuke siriseb“ tuleb lahendada kohe?</Heading>
          <p>
            Sirin tähendab, et kas rihm libiseb või laager kuivab. See ei parane iseenesest – veninud rihm venib edasi, kuiv laager kulub kiiremini ja lekked ei kao.
          </p>

          <Heading as="h2">Komplektne lahendus: rihm + rullikud + pinguti</Heading>
          <p>
            Nagu hammasrihma puhul, on mõistlik ka soonrihma juures vahetada <strong>rihm koos pinguti ja juhtrullikutega</strong>, kui vanus ja läbisõit on käes, ning kontrollida rihmarattaid ja lekkeid.
          </p>

          <Heading as="h2">Kokkuvõte: sirin on hoiatus, mitte taustamuusika</Heading>
          <p>
            <strong>Soonrihma hääl</strong> on signaal, et aeg on süsteem üle vaadata. Varajane sekkumine hoiab ära olukorra, kus jääd ilma laadimisest, roolivõimust ja võib-olla ka jahutusest keset sõitu.
          </p>
        </article>
      </main>
    </div>
  );
}
