import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "miks-hakkab-vanem-auto-rohkem-oli-votma";
const META_TITLE = "Miks hakkab vanem auto rohkem õli võtma ja kuidas seda lahendada?";
const META_DESCRIPTION =
  "Analüüsime, miks vanem auto hakkab rohkem õli võtma: leke, põlemine, kulunud tihendid ja kolvirõngad, vale õli või sõiduprofiil.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "õlikulu, vanem auto lekked, turbo tihendid",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMiksHakkabVanemAutoRohkemOliVotma() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-miks-hakkab-vanem-auto-rohkem-oli-votma",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Miks hakkab vanem auto rohkem õli võtma ja kuidas seda lahendada?</Heading>

          <p>
            Vanemate autode juures on <strong>õlikulu</strong> üks levinumaid teemasid. „Lisad liitri siia, liitri sinna“
            tundub alguses tühine, kuni ühel hetkel põleb õlirõhu tuli või tekib kap remont. Vaatame lahti peamised põhjused
            ja realistlikud lahendused.
          </p>

          <Heading as="h2">Lekib või põleb – kust alustada diagnoosi?</Heading>
          <p>
            Esmalt tuleb aru saada, kas õli <strong>kaob väljast või seest</strong>. Välised lekked jätavad jälje:
            mootoriplokk, karter, tihendipinnad, parkimiskoha laigud. Kui lekkeid ei paista, põleb õli tõenäoliselt
            silindrites ära.
          </p>

          <Heading as="h2">Tihendid ja simmerlingid: klassikaline vanusekahju</Heading>
          <p>
            Aastate jooksul kõvastuvad <strong>võlli- ja nukkvõlli simmerlingid, klapikambrikaane tihendid ja karteri tihend</strong>.
            Tulemuseks on „higistamine“, mis muutub ajapikku korralikuks lekkeks. Lahendus on tihendite vahetus, mitte ainult
            paksema õli kasutamine.
          </p>

          <Heading as="h2">Klapisääretihendid ja kolvirõngad – kui õli põleb ära</Heading>
          <p>
            Kui auto <strong>sinist suitsu</strong> teeb, eriti külmkäivitusel või pärast pikemat vaba jooksu, on kahtlusalused
            klapisääretihendid. Pidev sinakas suits kiirendusel viitab tihti kulunud kolvirõngastele. See on juba mehhaaniline
            teema, mille lahendus ei ole ainult õlitüübi vahetus.
          </p>

          <Heading as="h2">Vale viskoossus: liiga vedel õli väsinud mootoris</Heading>
          <p>
            Vanale, kulunud mootorile 0W-20 või muu väga vedel õli valimine on selge risk. Õli lipsab läbikulumiskohtadest
            lihtsalt läbi ja <strong>õlikulu tõuseb</strong>. Mõistlik samm on minna ühe astme võrra paksema õli peale
            (nt 5W-30 → 5W-40 või 10W-40), arvestades tootja miinimumnõuetega.
          </p>

          <Heading as="h2">Turbo ja PCV-süsteem – tihti unustatud süüdlased</Heading>
          <p>
            Turbomootoritel võib õli lekkida <strong>turbo võllitihenditest</strong> ja sattuda nii väljalaskesse kui
            sisselaskesse. Lisaks mängib rolli <strong>karteri tuulutuse (PCV) süsteem</strong>, mis ummistudes hakkab õli
            vale koha pealt kaasa tõmbama. Nende komponentide kontroll ja puhastus on kriitilised.
          </p>

          <Heading as="h2">Sõiduprofiil: lühikesed linnasõidud on õlile karmid</Heading>
          <p>
            Lühikesed otsad, kus mootor ei jõua töötemperatuurini, soodustavad <strong>kondensatsiooni ja kütuse sattumist õlisse</strong>.
            Õli vedeldub, kaotab kaitsevõime ja kulu kasvab. Lahendus: tihedam õlivahetus ja võimalusel regulaarselt pikemad sõidud.
          </p>

          <Heading as="h2">Millal on lahenduseks lihtsalt tihedam õlivahetus?</Heading>
          <p>
            Kui õlikulu on mõõdukas (nt alla 0,5 l / 1000 km) ja tehniliselt on kõik korras, võib vanema auto puhul olla
            mänguplaaniks <strong>lühendatud õlivahetusintervall</strong> ning veidi paksem õli. Kui kulu ületab 1 l / 1000 km,
            on enamasti mõistlik teha põhjalikum diagnostika.
          </p>

          <Heading as="h2">Kokkuvõte: õlikulu on sümptom, mitte diagnoos</Heading>
          <p>
            <strong>Vanema auto õlikulu</strong> ei ole automaatselt surmaotsus, aga see on signaal. Kui läheneda süsteemselt –
            kontrollida lekked, tihendid, rõngad, turbo ja PCV –, leiab enamasti kombinatsiooni, mis hoiab kulud kontrolli all ja
            lükkab suure remondi vajadust edasi.
          </p>
        </article>
      </main>
    </div>
  );
}

