import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "sildade-reguleerimine-parast-lookauke";
const META_TITLE = "Sildade reguleerimine – millal on sillastend pärast löökauke kohustuslik?";
const META_DESCRIPTION =
  "Selgitame, millal peab pärast löökauku, äärekivi või avariid kindlasti tegema sillastendi ning kuidas vale sillageomeetria kulutab rehve ja veermiku.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "sillastend, sillageomeetria, rehvikulumine",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogSildadeReguleerimineParastLookauke() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-sildade-reguleerimine-parast-lookauke",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Sildade reguleerimine – millal on sillastend pärast löökauke kohustuslik?</Heading>

          <p>
            Eesti teed ja löökaugud on veermikule karm test. Iga tugev pauk sillale võib lüüa sillageomeetria paigast. <strong>Sillastend</strong> ei ole kosmeetiline teenus – see mõjutab turvalisust, rehvikulu ja kütusekulu.
          </p>

          <Heading as="h2">Millised olukorrad nõuavad sillastendi?</Heading>
          <ul>
            <li>Oled sõitnud <strong>kõva löögiga auku</strong> või vastu äärekivi;</li>
            <li>Auto on olnud <strong>plekimõlkimise või avarii</strong> osaline;</li>
            <li>Pärast <strong>veermiku detailide vahetust</strong> (õõtsad, rooliotsad, amordid);</li>
            <li>Auto „ujub“, kipub <strong>ühele poole tõmbama</strong> või rool ei seisa otse.</li>
          </ul>

          <Heading as="h2">Mida vale sillageomeetria teeb?</Heading>
          <p>
            Kui varvas, camber või caster on paigast ära, kuluvad rehvid ebaühtlaselt, auto käitub ootamatult pidurdamisel ja kurvides, <strong>kütusekulu tõuseb</strong> ja veermiku detailid saavad suurema koormuse.
          </p>

          <Heading as="h2">Kuidas juht igapäevaselt aru saab?</Heading>
          <ul>
            <li>Rool ei ole sirgjooneliselt sõites otse;</li>
            <li>Auto <strong>tõmbab vasakule või paremale</strong>, eriti pidurdamisel;</li>
            <li>Roolis on lainetav liikumine või „ujumine“;</li>
            <li>Rehvidel on nähtav <strong>saehamba muster</strong> või kulunud serv.</li>
          </ul>

          <Heading as="h2">Miks teha sillastend ka ennetavalt?</Heading>
          <p>
            Korras sillageomeetria pikendab rehvide eluiga, annab turvalisema pidurdamise ja stabiilse käitumise kriisiolukorras ning vähendab veermiku ja roolisüsteemi koormust.
          </p>

          <Heading as="h2">Mida sillastend sisaldab?</Heading>
          <p>
            Professionaalne sillastend mõõdab ja korrigeerib esisilla varvast ning vajadusel camberit ja casterit, vaatab üle rooli asendi ja sümmeetria. Kui leitakse mehaanilisi vigu (lõtkud, kõverad detailid), tuleb need esmalt lahendada.
          </p>

          <Heading as="h2">Kokkuvõte: parem üks sillastend kui uued rehvid iga aasta</Heading>
          <p>
            Iga tugev löökaugukokkupõrge on põhjus sillageomeetria üle kontrollida. <strong>Sillastend</strong> on odavam kui uued rehvid, rääkimata veermikuremondist või halvast juhitavusest kriitilisel hetkel.
          </p>
        </article>
      </main>
    </div>
  );
}
