import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "vanemate-autode-jahutussusteemi-hooldus";
const META_TITLE = "Vanemate autode jahutussüsteemi hooldus – vead, mis lõhuvad mootori";
const META_DESCRIPTION =
  "Jahutussüsteemi hooldus vanematel autodel: levinumad vead, mis põhjustavad ülekuumenemist, tihendikahju ja mootori rikke.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "jahutussüsteem, ülekuumenemine, vanem auto",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogVanemateAutodeJahutussusteemiHooldus() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-vanemate-autode-jahutussusteemi-hooldus",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Vanemate autode jahutussüsteemi hooldus – vead, mis lõhuvad mootori</Heading>

          <p>
            Kui räägitakse <strong>vanema auto hooldusest</strong>, keskendutakse tihti õlivahetusele ja filtritele.
            Jahutussüsteem jääb tahaplaanile – kuni temperatuurinäidik punasesse sõidab. Tegelikult on just
            jahutussüsteem üks kriitilisemaid faktoreid mootori eluea juures.
          </p>

          <Heading as="h2">Viga nr 1: „Kui radikas lekib, paneme kraani vett sisse“</Heading>
          <p>
            Puhas vesi ei kaitse süsteemi korrosiooni ja külmumise eest. Vanas mootoris tähendab see roostet,
            ummistunud kanaleid ja pragunenud plokki. <strong>Õige jahutusvedelik</strong> koos lisanditega ei ole
            luksus, vaid standard.
          </p>

          <Heading as="h2">Viga nr 2: Jahutusvedelikku ei vahetata kunagi</Heading>
          <p>
            Jahutusvedelik ei ole igavene. Lisandid lagunevad, pH muutub ja vedelik muutub söövitavaks. Vanematel
            autodel, mille süsteem on niigi õrn, on <strong>vahetamata vedelik</strong> otsene risk ploki, radika ja
            tihendite tervisele.
          </p>

          <Heading as="h2">Viga nr 3: Termostaat on kinni – ja seda ignoreeritakse</Heading>
          <p>
            Kui mootor ei jõua töötemperatuurini või läheb see kiiresti punasesse, on kahtlustatav <strong>termostaat</strong>.
            Avatud asendis jookseb mootor liiga külmalt, suletud asendis kuumeneb üle. Mõlemad kiirendavad kulumist ja tõstavad
            kütusekulu.
          </p>

          <Heading as="h2">Viga nr 4: Radiaator ja paisupaak on seest täis muda</Heading>
          <p>
            Vanematel autodel koguneb aastatega <strong>setet ja roostet</strong>. Kui radiaatori kanalid on kinni, ei piisa
            ühestki uuest ventilaatorist ega termostaadist. Lahendus: süsteemi loputus, vajadusel radika vahetus.
          </p>

          <Heading as="h2">Viga nr 5: Ventilaator ei lülitu õigel ajal tööle</Heading>
          <p>
            Jahutusventika töö sõltub <strong>temperatuuriandurist, releedest ja juhtmestikust</strong>. Vanas autos võivad
            kõik kolm olla probleemsed. Kui ventikas ei tööta, kuumeneb mootor ummikutes või koormuse all väga kiiresti üle.
          </p>

          <Heading as="h2">Viga nr 6: Veesärk ja plokikaanetihend saavad löögi</Heading>
          <p>
            Korduvalt ülekuumenenud mootoril annab varem või hiljem alla <strong>plokikaanetihend</strong>. Jahutusvedelik
            satub silindritesse või õli hulka. Kui paisupaagis on õlijäljed või summutist tuleb valget auru, on kahju juba tehtud.
          </p>

          <Heading as="h2">Kuidas vanema auto jahutussüsteemi õigesti hooldada?</Heading>
          <ul>
            <li>Vaheta jahutusvedelikku tootja või töökoja soovitatud intervalli järgi (tihti 2–4 aastat).</li>
            <li>Kontrolli regulaarselt radiaatori, voolikute ja paisupaagi seisukorda.</li>
            <li>Reageeri koheselt, kui temperatuurinäidik käitub teisiti kui tavaliselt.</li>
            <li>Kui ostad kasutatud vana auto, lase süsteem kohe üle vaadata ja vajadusel loputada.</li>
          </ul>

          <Heading as="h2">Kokkuvõte: jahutussüsteem on kindlustus mitte kulu</Heading>
          <p>
            <strong>Vanema auto jahutussüsteemi hooldus</strong> on odav võrreldes ploki või plokikaane remondiga.
            Kui näed jahutusvedelikku kui investeeringut, mitte kui vedelikku, mis „lihtsalt on“, pikendad mootori eluiga
            väga konkreetselt.
          </p>
        </article>
      </main>
    </div>
  );
}

