import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "mootori-lekked";
const META_TITLE = "Mootori lekked – millal piisab tihendi vahetusest ja millal on probleem suurem?";
const META_DESCRIPTION =
  "Aitame aru saada, millal on mootori õlileke lahendatav tihendi vahetusega ja millal viitab see juba tõsisemale mootoriprobleemile.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "mootori lekked, tihendi vahetus, karterirõhk",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMootoriLekked() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-mootori-lekked",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Mootori lekked – millal piisab tihendi vahetusest ja millal on probleem juba suurem?</Heading>

          <p>
            Õlilaik parkimiskohas või õline mootoriplokk on vanematel autodel tavaline vaatepilt. Küsimus on: kas tegemist on <strong>tüüpilise tihendilekiga</strong>
            või on taustal juba tõsisem mehhaaniline teema, mis vajab sügavamat sekkumist.
          </p>

          <Heading as="h2">Klapikambrikaane tihend – tüüpiline ja enamasti lihtsam juhtum</Heading>
          <p>
            Kõrgel mootoril olev <strong>klapikambrikaane tihend</strong> hakkab ajaga kõvastuma ja pragunema. Tulemuseks on õli „higistamine“ mootoriploki külgedele
            ja vahel isegi küünlapesadesse. Enamasti piisab tihendi vahetusest ja pinnapuhastusest – tingimusel, et õlirõhk on normaalne.
          </p>

          <Heading as="h2">Karteri tihend ja karteripõhi</Heading>
          <p>
            <strong>Karteri tihendi leke</strong> jätab enamasti õlilaigud otse auto alla. Kui karter on saanud lööke (äärekivi, kivi teel), võib ka karter ise olla mõranenud või kõver.
            Siin ei ole mõtet ainult tihendit süüdistada – vaja on hinnata ka karteri seisukorda.
          </p>

          <Heading as="h2">Simmerlingid vänt- ja nukkvõllil</Heading>
          <p>
            Kulunud <strong>simmerlingid</strong> hakkavad lekima väntvõlli otstest või nukkvõlli juurest. See võib määrida rihma- või kettasüsteemi, sidurit ja muid detaile.
            Kui leke on suur, võib õlitaseme langus muutuda juba ohtlikuks. Sageli lahendatav simmerlingi vahetusega, aga vajadusel tuleb hinnata ka võlli ja laagrite kulumist.
          </p>

          <Heading as="h2">Millal on leke sümptom, mitte põhjus?</Heading>
          <p>
            Kui mootoris on <strong>liiga kõrge karterirõhk</strong> (näiteks kulunud kolvirõngaste ja kehva karteri tuulutuse tõttu), surutakse õli tihenditest lihtsalt välja.
            Sellisel juhul ei piisa tihendi vahetusest – see hakkab uuesti lekkima, kuni karterirõhk ja rõngaste seisukord on korras.
          </p>

          <Heading as="h2">Õli ja jahutusvedeliku segunemine</Heading>
          <p>
            Kui paisupaagis on õlijäljed või õlis on piimjas toon, ei ole tegu enam lihtsa tihendilekkega. See viitab tihti <strong>plokikaanetihendi veale või ploki/pragude probleemile</strong>.
            Siin ei aita „tihend vahetusse“ mõtteviis, vaid tuleb teha põhjalik diagnostika.
          </p>

          <Heading as="h2">Millal on mõistlik remont edasi lükata ja lihtsalt jälgida?</Heading>
          <p>
            Väga väike „higistamine“, mis ei tekita parkimiskohta märgatavaid laike ja ei mõjuta õlitaset, võib vanemal autol olla <strong>aktiivselt jälgitav, mitte kohe remonditav</strong> teema.
            Oluline on, et omanik mõõdaks regulaarselt õlitaset ja jälgiks, kas leke ajas süveneb.
          </p>

          <Heading as="h2">Kokkuvõte: tihendivahetus on mõistlik, kui põhjus on kontrolli all</Heading>
          <p>
            <strong>Mootori õlileke</strong> võib olla nii lihtne tihendiprobleem kui ka signaal sügavamast kulumisest või üleliigsest karterirõhust. Enne töö tegema hakkamist tasub hinnata tervikpilti –
            muidu vahetad ainult tagajärge, mitte põhjust.
          </p>
        </article>
      </main>
    </div>
  );
}
