import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "mootoripadjad";
const META_TITLE = "Mootorikinnituspadjad: miks lõtv padi muudab auto logiseks ja jõuetuks?";
const META_DESCRIPTION =
  "Selgitame, miks mootoripadjad määravad auto mugavuse ja juhitavuse, millised sümptomid viitavad väsinud patjadele ning miks remonti ei tasu edasi lükata.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "mootoripadjad, vibratsioon, jõuülekanne",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMootoripadjad() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-mootoripadjad",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <header>
            <Heading as="h1">Mootorikinnituspadjad: miks lõtv padi muudab auto logiseks ja jõuetuks?</Heading>
            <h2>Alternatiivsed pealkirjad</h2>
            <ul>
              <li>Mootoripadjad ja vibratsioon: miks muutub auto “plekk-kastiks”?</li>
              <li>Lõtv mootoripadi = logisev auto: sümptomid ja riskid</li>
              <li>Miks mootoripatjade ignoreerimine rikub salongi mugavuse ja veermiku?</li>
            </ul>
            <p>
              Mootorikinnituspadjad on tüüpiline “silma alt ära, meelest ära” komponent. Samas dikteerivad just need, kas su auto tundub kindel ja kompaktne või logisev ja vibratsioonist läbi põrutatud. Kui padi on lõtv, saad iga gaasivajutuse ja käiguvahetuse “kogu kupatusega” salongi kätte.
            </p>
          </header>

          <section>
            <Heading as="h2">Mis rolli mootoripadjad tegelikult mängivad?</Heading>
            <p>Mootoripadi ei ole lihtsalt kummitükk, mis hoiab jõuallikat paigal. Selle võtmeülesanded:</p>
            <ul>
              <li><strong>Vibratsiooni summutamine</strong> – mootorivõbelus ei jõua salongi.</li>
              <li><strong>Pöörete ja pöördemomendi kontroll</strong> – jõud kandub ratasteni, mitte keresse.</li>
              <li><strong>Jõuülekande kaitse</strong> – liigset mootoriliikumist ei jõua pooltelgede ja kardaanini.</li>
            </ul>
          </section>

          <section>
            <Heading as="h2">Tüüpilised sümptomid</Heading>
            <ul>
              <li><strong>Vibratsioon salongis:</strong> tühikäigul väriseb rool, istmed, mõnikord isegi armatuur.</li>
              <li><strong>Kolin ja löögid käiguvahetusel:</strong> mootor liigub liiga palju, jõuülekanne saab löögi.</li>
              <li><strong>Jõuetunne:</strong> gaasi vajutades läheb esmalt energia mootori kõigutamisele.</li>
              <li><strong>Veermiku lisakoormus:</strong> liigne mootoriliikumine koormab pooltelgi ja pukse.</li>
            </ul>
          </section>

          <section>
            <Heading as="h2">Miks mootoripatjadega venitamine on halb äriotsus?</Heading>
            <p>
              Väsinud mootoripadi on suhteliselt odav detail, kuid selle mõju on proportsionaalselt väga suur. Kui lased sel liiga pikalt “ära vajuda”, maksad hiljem kinni lisakoormusest kulunud veermiku- ja roolikomponendid, pooltelje ja käigukasti lisakulumise ning salongi ebamugavuse.
            </p>
          </section>

          <section>
            <Heading as="h2">Tunned, et auto on muutunud logiseks ja vibrab üle?</Heading>
            <p>
              <a href="/kontakt">Broneeri aeg Nisbelis</a> mootoripatjade kontrolliks. Teeme testisõidu, vaatame padjad üle ning pakume välja lahenduse, mis taastab auto algse kompaktse tunde.
            </p>
          </section>
        </article>
      </main>
    </div>
  );
}
