import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "hammasrihma-komplekt";
const META_TITLE = "Hammasrihma komplekt – miks ainult rihma vahetamine on halb plaan?";
const META_DESCRIPTION =
  "Selgitame, mis on hammasrihma komplekt, miks sinna kuuluvad pingutid ja rullikud ning miks ainult rihma vahetamine on riskantne kokkuhoid.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "hammasrihma komplekt, pingutid, rullikud",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogHammasrihmaKomplekt() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-hammasrihma-komplekt",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Hammasrihma komplekt – miks ainult rihma vahetamine on halb plaan?</Heading>

          <p>
            Tihti küsitakse: „Kas ei saa ainult rihma ära vahetada, siis on odavam?“ Tehniline vastus: saab, aga ei ole mõistlik. <strong>Hammasrihma komplekt</strong> sisaldab rihma, pinguteid ja rullikuid põhjusega.
          </p>

          <Heading as="h2">Mida komplekt sisaldab?</Heading>
          <p>
            Sõltuvalt mootorist sisaldab komplekt tavaliselt <strong>hammasrihma</strong>, <strong>pingutusrullikuid</strong>, <strong>juhtrullikuid</strong> ja tihti ka kinnitusi ning polte.
          </p>

          <Heading as="h2">Miks pingutid ja rullikud on kriitilised?</Heading>
          <p>
            Kui vana rullik või pinguti jookseb kinni, hakkab rihm <strong>üle libisema või hammaste pealt maha hüppama</strong>. Tulemus on sama, mis rihma purunemisel – <strong>mootorikahjustus</strong>.
          </p>

          <Heading as="h2">Vana rullik uue rihmaga = uus risk</Heading>
          <p>
            Uus rihm töötab pingul ja elastne. Vana rullik võib olla laagriga, mis on kuivanud või roostes. Mõne tuhande kilomeetri pärast hakkab ta häälitsema või kinni jooksma.
          </p>

          <Heading as="h2">Kokkuhoid täna, topeltkulu homme</Heading>
          <p>
            Kui vahetad ainult rihma ja hiljem sureb rullik, tuleb uuesti kogu esiosa lahti võtta, panna uus komplekt ja maksta uuesti tööraha. Ehk: kaks korda tööd, üks „kokkuhoid“.
          </p>

          <Heading as="h2">Kokkuvõte: hammasrihma töö tehakse korraga ja korralikult</Heading>
          <p>
            <strong>Hammasrihma komplekti vahetus</strong> tähendab kogu süsteemi korrastamist – mitte ainult ühe jubina väljavahetamist. See on ainus mõistlik viis vähendada riski, et väike rullik viib kaasa suure mootoriremondi.
          </p>
        </article>
      </main>
    </div>
  );
}
