import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "rattalaagrid-ja-vibratsioon";
const META_TITLE = "Rattalaagrid ja vibratsioon – millal muutub müra ohutusriskiks?";
const META_DESCRIPTION =
  "Rattalaagri undamine ja vibratsioon ei ole süütu heli. Õpi varakult ära tundma ohtlikku laagrit ja miks selle vahetusega ei tohi venitada.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "rattalaager, vibratsioon, undamine",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogRattalaagridJaVibratsioon() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-rattalaagrid-ja-vibratsioon",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Rattalaagrid ja vibratsioon – millal muutub müra ohutusriskiks?</Heading>

          <p>
            Esialgu on see ainult kerge <strong>undamine või urin</strong>. Mõne aja pärast muutub see valjemaks, lisandub vibratsioon ja lõpuks võib ratas sõna otseses mõttes kinni joosta. Rattalaager on komponent, mille vahetust ei tasu edasi lükata.
          </p>

          <Heading as="h2">Kuidas rattalaagri müra ära tunda?</Heading>
          <ul>
            <li>Monotoonne <strong>undamine, mis kasvab kiirusega</strong> (50–90 km/h piirkonnas);</li>
            <li>Heli muutub kurvis – kui keerates paremale muutub vasak pool lärmakam ja vastupidi;</li>
            <li>Müra meenutab lennuki tõusmise heli või „mõminat“.</li>
          </ul>

          <Heading as="h2">Mida tähendab laagri lõtk?</Heading>
          <p>
            Kui auto on tõstetud, saab ratas käega kõigutades hinnata, kas on <strong>lõtku</strong>. Lõtk rattas mõjutab rehvide kulumist, juhitavust, pidurdust ja ABS-anduri tööd.
          </p>

          <Heading as="h2">Mida kauem sõidad, seda suurem on kahju</Heading>
          <p>
            Kulunud rattalaager kuumeneb üle ja võib kinni joosta, lõhkuda <strong>rummu, piduriketta ja isegi poldiühendused</strong> ning tekitada vibratsiooni, mis koormab üle veermiku ja roolisüsteemi.
          </p>

          <Heading as="h2">Miks vahetus ei ole ainult mugavusküsimus?</Heading>
          <p>
            Kui laager laguneb sõidu ajal lõplikult, võib ratas kiiluda kinni või lausa eralduda – need on reaalsed ohud, mis lõppevad vaakumtaoliselt kontrolli kaotamisega.
          </p>

          <Heading as="h2">Millal lasta veermik üle kontrollida?</Heading>
          <p>
            Kui märkad uut ühtlast undamist, vibratsiooni kindlal kiirusel või lõtku ratta juures, on aeg tulla <strong>veermikukontrolli</strong> ja lasta rattalaagrid üle hinnata.
          </p>

          <Heading as="h2">Kokkuvõte: rattalaager on odav võrreldes riskiga</Heading>
          <p>
            <strong>Rattalaagri vahetus</strong> on kordades odavam kui hilisem kahju veljele, rummule, pidurisüsteemile ja potentsiaalne avarii. Müra ei kao iseenesest – see lõpeb kas remondi või rikkega. Tark on valida esimene variant.
          </p>
        </article>
      </main>
    </div>
  );
}
