import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "veepump-ja-hammasrihm";
const META_TITLE = "Veepump ja hammasrihm koos – miks seda korraga teha?";
const META_DESCRIPTION =
  "Paljudel mootoritel käib veepump hammasrihma pealt. Selgitame, miks on mõistlik vahetada veepump koos hammasrihmaga, mitte oodata järgmise rikkeni.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "veepump, hammasrihm, jahutussüsteem",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogVeepumpJaHammasrihm() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-veepump-ja-hammasrihm",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Veepump ja hammasrihm koos – miks seda korraga teha?</Heading>

          <p>
            Paljudel mootoritel käitab <strong>veepumpa hammasrihm</strong>. See tähendab, et veepumba rikkega võib lõhkuda ka rihma. Seetõttu soovitab nii tootja kui ka terve mõistus teha hammasrihma töö koos veepumba vahetusega.
          </p>

          <Heading as="h2">Kuidas veepump on hammasrihma küljes?</Heading>
          <p>
            Veepump asub tihti samas ajamikomplektis: rihm jookseb üle pumba hammasrattast, pumba laager ja tihend peavad vastu pidama sama kaua kui rihm ning kui pump kinni jookseb, saab <strong>rihm šoki</strong>.
          </p>

          <Heading as="h2">Mis juhtub, kui veepump jäetakse vahetamata?</Heading>
          <p>
            Kui vana pump jäetakse alles, võib mõne aja pärast tekkida <strong>leke</strong> või jookseb laager kinni. Hammasrihm võib kahjustuda või maha hüpata – tulemuseks mootorikahjustus.
          </p>

          <Heading as="h2">Töömaht: kaks korda sama tööd ei tasu</Heading>
          <p>
            Veepumba juurde jõudmiseks tuleb eemaldada rihmakatted, võtta maha osa ajamikomponente ja välja lasta jahutusvedelik. Kui seda kõike teha hiljem uuesti ainult pumba pärast, maksad kaks korda sama töö eest.
          </p>

          <Heading as="h2">Veepump komplektis – kindel lahendus</Heading>
          <p>
            Paljud kvaliteetsed <strong>hammasrihma komplektid tulevad koos veepumbaga</strong>. See tagab, et kõik komponendid on omavahel sobivad ja sama tootja kvaliteeditase on ühtlane.
          </p>

          <Heading as="h2">Kokkuvõte: üks suur töö, mitte kolm väikest</Heading>
          <p>
            <strong>Veepumba vahetus koos hammasrihmaga</strong> on kuluefektiivne ja tehniliselt loogiline. Üks hoolikas töö tänasel päeval on alati odavam kui kolm eraldi lappimist järgmise paari aasta jooksul.
          </p>
        </article>
      </main>
    </div>
  );
}
