import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "check-engine-tuli-poleb";
const META_TITLE = "Mootori “check engine” tuli põleb – millal võib sõita edasi ja millal tuleb auto seisma jätta?";
const META_DESCRIPTION =
  "Selgitame, mida tähendab mootori check engine tuli, millal võib ettevaatlikult edasi sõita ja millal peab auto kohe seisma jätma, et vältida kallist mootoriremonti.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "check engine, süütekatkestus, diagnostika",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogCheckEngineTuliPoleb() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-check-engine-tuli-poleb",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Mootori “check engine” tuli põleb – millal võib sõita edasi ja millal tuleb auto seisma jätta?</Heading>

          <p>
            Armatuurlaual süttiv <strong>“check engine”</strong> tuli ei ole dekoratsioon. See on mootori juhtploki signaal, et midagi ei tööta nii, nagu peaks. Küsimus on: kas on kriis nüüd ja kohe, või saad rahulikult teenindusse sõita?
          </p>

          <Heading as="h2">Esimene reegel: vilgub või põleb?</Heading>
          <p>Vaheta kiiresti mõtteviisi „ah, küll sõidab“ mentaliteedilt riskijuhtimisele:</p>
          <ul>
            <li><strong>Tuli põleb pidevalt</strong> – mootoris on viga, aga süsteem suudab end veel ise ohjeldada. Tavaliselt saab ettevaatlikult töökojani sõita.</li>
            <li><strong>Tuli vilgub</strong> – kriitiline viga, tihti süütekatkestus. Iga katkise süütega põlemistsükkel tapab <strong>katalüsaatorit ja DPF-i</strong>. See on STOP-situatsioon.</li>
          </ul>

          <Heading as="h2">Mida teha, kui tuli süttib sõidu ajal?</Heading>
          <ol>
            <li>Vaata, kas tuli <strong>vilgub või põleb pidevalt</strong>.</li>
            <li>Jälgi, kas auto käitub tavapäraselt või on jõuetus, värinad, ebastabiilne tühikäik või ebatavalised helid.</li>
            <li>Kontrolli teisi ohutulesid: <strong>õlirõhk ja jahutusvedeliku temperatuur</strong>. Kui need on korras, on üldjuhul aega rahulikult teenindusse sõita.</li>
          </ol>

          <Heading as="h2">Millal võib ettevaatlikult edasi sõita?</Heading>
          <p>Ettevaatlik sõit töökojani on enamasti okei, kui tuli ei vilgu, auto ei värise ega tõmble, võimsust on veidi vähem, kuid auto liigub ühtlaselt ning jahutustemp ja õlituli on normis.</p>

          <Heading as="h2">Millal tuleb auto kohe seisma jätta?</Heading>
          <p>STOP – ära mängi kangelast – kui:</p>
          <ul>
            <li><strong>check engine vilgub</strong> ja auto väriseb;</li>
            <li>koos check engine’iga süttib <strong>õlirõhu tuli</strong> või temperatuur läheb punasesse;</li>
            <li>mootor teeb metallilist kolinat või jõudlus kukub ohtlikult madalaks.</li>
          </ul>

          <Heading as="h2">Miks ei tasu tuld „püsivaks taustaks“ jätta?</Heading>
          <p>
            Pidevalt põlev <strong>check engine</strong> tähendab hädaolukorra režiimi, kõrgemat kütusekulu, suuremat koormust katalüsaatorile, DPF-ile ja turbole ning järgmine viga võib jääda märkamatuks.
          </p>

          <Heading as="h2">Diagnostika – mitte ainult koodi lugemine</Heading>
          <p>Õige lähenemine: veakoodid loetakse välja skänneriga, tehakse proovikäik ja live-andmete vaatlus ning otsitakse <strong>põhjus, mitte ainult sümptom</strong>.</p>

          <Heading as="h2">Kokkuvõte</Heading>
          <p>
            <strong>Check engine tuli</strong> on varajane hoiatus. Kui tuli põleb, aga auto käitub normaalselt, sõida ettevaatlikult diagnostikasse. Kui tuli vilgub või lisandub õli/temperatuuri probleem, jäta auto seisma ja kasuta puksiiri. Odav diagnostika täna on odavam kui mootoriremont homme.
          </p>
        </article>
      </main>
    </div>
  );
}
