import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "odavad-jarelturu-varuosad-vs-originaal";
const META_TITLE = "Odavad järelturu varuosad vs originaal – vanema auto strateegia";
const META_DESCRIPTION =
  "Võrdleme odavaid järelturu varuosi ja originaaldetaile ning aitame vanema auto omanikul leida mõistliku hooldusstrateegia.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "järelturu varuosad, originaalvaruosad, hooldusstrateegia",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogOdavadJarelturuVaruosadVsOriginaal() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-odavad-jarelturu-varuosad-vs-originaal",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Odavad järelturu varuosad vs originaal – vanema auto strateegia</Heading>

          <p>
            Iga vanema auto omanik jõuab küsimuseni: kas <strong>tõsta raha originaalosadele</strong> või kasutada soodsamaid järelturu detaile?
            Õige vastus ei ole must-valge – see sõltub sõlmest, auto väärtusest ja sellest, kui kaua plaanid autot veel pidada.
          </p>

          <Heading as="h2">Kus ei tohi kvaliteedi pealt kokku hoida?</Heading>
          <p>On sõlmi, kus odavaim variant on objektiivselt halb otsus:</p>
          <ul>
            <li><strong>Pidurid</strong> – kettad, klotsid, pidurivoolikud. Odav klots võib viliseda, tolmutada ja kuluda kiiresti;</li>
            <li><strong>Vedrustus ja veermik</strong> – amordid, šarniirid, pukid, rooliotsad;</li>
            <li><strong>Roolisüsteem</strong> – roolilatt, roolivarras.</li>
          </ul>
          <p>
            Nendes kohtades mõjutab detail otseselt ohutust ja juhitavust. Soovitus: kasutada kas kvaliteetset järelturu brändi või originaali, mitte tundmatu „white label“ toodet.
          </p>

          <Heading as="h2">Kus on järelturu osa täiesti mõistlik valik?</Heading>
          <p>
            Väga paljud <strong>filtrid, andurid ja plastikdetailid</strong> on järelturul piisava kvaliteediga. Näited, kus premium-järelturu tootja sobib hästi:
          </p>
          <ul>
            <li>õhufilter, salongifilter, kütusefilter;</li>
            <li>mõned elektriosad (nt tuntud tootjate andurid);</li>
            <li>kere plastikud, katted, kinnitused, klambrid.</li>
          </ul>

          <Heading as="h2">Originaal ei tähenda alati „tehase parim“ – vaid kindlat standardit</Heading>
          <p>
            Originaalosa eelis on see, et see vastab kindlasti <strong>autotootja standardile</strong> ja sobivusele. Aga tihti toodab seda sama detaili ka järelturu bränd,
            ainult teise karbiga. Hea töökoja roll on aidata eristada, milline järelturu bränd on tegelikult sama liini toode.
          </p>

          <Heading as="h2">Auto vanus ja plaanitav kasutusaeg</Heading>
          <p>
            Kui plaanid vanemat autot pidada veel 1–2 aastat, ei ole mõistlik kõikjale panna kallist originaali. Kui aga <strong>mootor ja kere on heas seisus</strong>
            ning plaan on autot pikemalt hoida, võib kriitilistes sõlmedes originaal investeeringuna ära tasuda.
          </p>

          <Heading as="h2">Odav detail, kallis vahetus</Heading>
          <p>
            Mõnes kohas on detail odav, aga töö kallis (näiteks sidur, mõni sügaval olev tihend, armatuuri alt vahetatav radikas). Sellisel juhul on mõistlik <strong>panustada ühekordselt kvaliteetsesse detaili</strong>,
            mitte mängida odava varuosaga „vaatame, kaua kestab“ mängu.
          </p>

          <Heading as="h2">Kokkuvõte: strateegia, mitte loosiratas</Heading>
          <p>
            <strong>Vanema auto varuosapoliitika</strong> peab olema kalkuleeritud: ohutuse ja suure töömahuga sõlmedes kvaliteetne bränd või originaal, vähem kriitilistes kohtades hea järelturu osa.
            Nii püsib auto töökindel, ilma et kulud läheksid ebamõistlikult suureks.
          </p>
        </article>
      </main>
    </div>
  );
}
