import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "7-marki-et-sinu-auto-vajab-kiiret-olivahetust";
const META_TITLE = "7 märki, et sinu auto vajab kiiret õlivahetust";
const META_DESCRIPTION =
  "Seitse konkreetset märki, mille järgi ära tunda, et auto vajab kiiret õlivahetust – helid, lõhn, õlikulu, näidikud ja käivitumisprobleemid.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "õlivahetus, hooldus, õlirõhu hoiatus",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function Blog7MarkiEtAutoVajabKiiretOlivahetust() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-7-marki-et-sinu-auto-vajab-kiiret-olivahetust",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">7 märki, et sinu auto vajab kiiret õlivahetust</Heading>

          <p>
            <strong>Õlivahetust</strong> kiputakse edasi lükkama seni, kuni midagi „päriselt juhtub“. Probleem on selles,
            et kui sümptomid lõpuks välja löövad, on kahju sageli juba tehtud. Allpool on seitse konkreetset märki, mille
            puhul ei tasu enam oodata.
          </p>

          <Heading as="h2">1. Mootor teeb ebatavalist klõbinat või tiksumist</Heading>
          <p>
            Külmkäivitusel tekkiv selge tiksumine, mis ei kao mõne sekundiga, viitab tihti sellele, et{" "}
            <strong>mootoriõli on liiga õhuke või väsinud</strong>. Hüdrotõukurid ja nukkvõll saavad esimese löögi.
          </p>

          <Heading as="h2">2. Õli on vardal must ja paks</Heading>
          <p>
            Õli ei pea olema kristallselge, aga kui see on juba kiiresti pärast vahetust täiesti must ja väga paks, on{" "}
            <strong>lisandipakett läbi põlenud</strong> ning õli ei puhasta ega kaitse mootorit enam efektiivselt.
          </p>

          <Heading as="h2">3. Õlirõhu hoiatustuli vilgub või süttib</Heading>
          <p>
            Isegi lühiajaline <strong>õlirõhu kadu</strong> on punane alarm. Põhjus võib olla madal õlitase, vale
            viskoossus, väsinud õli või koguni ummistunud sõela kombinatsioon. Reaktsioon: mootor seisma ja kontroll
            töökojas, mitte „sõidan koju ära“.
          </p>

          <Heading as="h2">4. Kütusekulu on tõusnud ilma selge põhjuseta</Heading>
          <p>
            Väsinud õli suurendab hõõrdumist. Kui sõiduprofiil on sama, aga <strong>kütusekulu on 0,5–1 l/100 km kõrgem</strong>,
            tasub kontrollida nii õliseisundit kui ka õlivahetuse ajalugu.
          </p>

          <Heading as="h2">5. Mootor kuumeneb kergemini üle</Heading>
          <p>
            Õli vastutab osaliselt ka mootori jahutuse eest. Kui <strong>temperatuurinäidik liigub tavapärasest kõrgemale</strong>{" "}
            ja jahutussüsteem on korras, võib probleem peituda vananenud õlis, mis ei juhi enam soojust efektiivselt.
          </p>

          <Heading as="h2">6. Käivitamine on muutunud raskemaks, eriti külmaga</Heading>
          <p>
            Liiga paks või valesti valitud viskoossusega õli muudab külmkäivituse raskeks. Starter peab kauem töötama,
            aku saab korraliku koormuse ja mootor kulub. <strong>Õigeaegne õlivahetus</strong> koos sobiva õliga teeb vahe.
          </p>

          <Heading as="h2">7. Õlivahetusintervall on ammu ületatud</Heading>
          <p>
            Kui hooldusraamatus on kirjas 15 000 km ja sina sõidad juba 22 000 km, on küsimus retooriline. Eriti kriitiline
            on see <strong>vanemate autode</strong> ja linnasõiduga, kus õli vananeb kiiremini kui tootja ideaalsena eeldas.
          </p>

          <Heading as="h2">Kokkuvõte: ära oota, kuni mootor ise „räägib“</Heading>
          <p>
            Kui kasvõi kaks neist sümptomitest on korraga mängus, on <strong>kiire õlivahetus</strong> odavam ja
            mõistlikum kui hilisem mootori remont. Hooldusgraafik ei ole paberimäärus – see on odavaim kindlustus, mis
            mootoril olla saab.
          </p>
        </article>
      </main>
    </div>
  );
}

